mapper.select:
SELECT r.id, r.reporter_id, r.reported_user_id, r.product_id, r.order_id, r.type, r.description, r.evidence_images, r.status, r.resolution, r.deleted_at, r.resolved_at, r.created_at, r.updated_at, reporter.nickname AS reporter_nickname, reporter.avatar AS reporter_avatar, reported.nickname AS reported_nickname, reported.avatar AS reported_avatar FROM reports r JOIN users reporter ON r.reporter_id = reporter.id JOIN users reported ON r.reported_user_id = reported.id
r.deleted_at IS NULL
AND r.status = #{status}
AND r.type = #{type}
ORDER BY r.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM reports r

    r.deleted_at IS NULL

        AND r.status = #{status}


        AND r.type = #{type}
